            guard response == .OK, let folderURL = panel.url else {
                return
            }

            Task { @MainActor in
                self?.setWatchedFolder(folderURL)
            }
        }
    }

    func setWatchedFolder(_ folderURL: URL) {
        let wasWatching = isWatching
        stop()
